```python
import sys

def solve():
    n, s, r = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))
    ans = 0
    for i in range(n):
        total = 0
        for j in range(i, n):
            total += a[j]
            if total <= s and (max(a[i:j+1]) - min(a[i:j+1])) <= r:
                ans += 1
            if total > s:
                break
    print(ans)

if __name__ == "__main__":
    solve()
